#include <stdio.h>
#include <stdlib.h>

#define MAX 100

typedef struct {
  int src, dest, weight;
} Edge;

typedef struct {
  int parent[MAX];
  int rank[MAX];
} DisjointSet;

void initDisjointSet(DisjointSet* ds, int vertices) {
  for (int i = 0; i < vertices; i++) {
    ds->parent[i] = i;
    ds->rank[i] = 0;
  }
}

int find(DisjointSet* ds, int i) {
  if (ds->parent[i] != i) {
    ds->parent[i] = find(ds, ds->parent[i]);
  }
  return ds->parent[i];
}

void unionSet(DisjointSet* ds, int x, int y) {
  int xroot = find(ds, x);
  int yroot = find(ds, y);
  if (ds->rank[xroot] < ds->rank[yroot]) {
    ds->parent[xroot] = yroot;
  } else if (ds->rank[xroot] > ds->rank[yroot]) {
    ds->parent[yroot] = xroot;
  } else {
    ds->parent[yroot] = xroot;
    ds->rank[xroot]++;
  }
}

int compare(const void* a, const void* b) {
  return ((Edge*)a)->weight - ((Edge*)b)->weight;
}

void kruskal(Edge* edges, int edgeCount, int vertices) {
  qsort(edges, edgeCount, sizeof(Edge), compare);
  DisjointSet ds;
  initDisjointSet(&ds, vertices);
  int totalWeight = 0;
  printf("MST Edges:\n");
  for (int i = 0; i < edgeCount; i++) {
    int u = find(&ds, edges[i].src);
    int v = find(&ds, edges[i].dest);
    if (u != v) {
      printf("%d - %d (weight: %d)\n", edges[i].src, edges[i].dest, edges[i].weight);
      totalWeight += edges[i].weight;
      unionSet(&ds, u, v);
    }
  }
  printf("Total MST weight: %d\n", totalWeight);
}

int main() {
  int vertices = 5;
  int edgeCount = 7;
  Edge edges[] = {
    {0, 1, 4}, {0, 2, 2}, {1, 2, 5}, {1, 3, 10}, {2, 3, 3}, {2, 4, 8}, {3, 4, 6}
  };
  kruskal(edges, edgeCount, vertices);
  return 0;
}
// Output: 
// MST Edges:
// 0 - 2 (weight: 2)
// 2 - 3 (weight: 3)
// 0 - 1 (weight: 4)
// 3 - 4 (weight: 6)
// Total MST weight: 15

